&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;चैंपियंस ट्रॉफी 2025: भारत ने न्यूज़ीलैंड को चार विकेट से हराया।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;123&quot; data-start=&quot;25&quot;&gt;&lt;strong data-end=&quot;37&quot; data-start=&quot;28&quot;&gt;भारत&lt;/strong&gt; ने &lt;strong data-end=&quot;75&quot; data-is-only-node=&quot;&quot; data-start=&quot;46&quot;&gt;ICC चैंपियंस ट्रॉफी 2025&lt;/strong&gt; का फाइनल &lt;strong data-end=&quot;98&quot; data-start=&quot;85&quot;&gt;4 विकेट&lt;/strong&gt; से &lt;strong data-end=&quot;122&quot; data-start=&quot;107&quot;&gt;न्यूज़ीलैंड&lt;/strong&gt; के खिलाफ जीता।&lt;/li&gt;
	&lt;li data-end=&quot;177&quot; data-start=&quot;124&quot;&gt;&lt;strong data-end=&quot;155&quot; data-start=&quot;127&quot;&gt;टूर्नामेंट का सर्वश्रेष्ठ खिलाड़ी&lt;/strong&gt;: &lt;strong data-end=&quot;176&quot; data-is-only-node=&quot;&quot; data-start=&quot;157&quot;&gt;राचिन रविन्द्र&lt;/strong&gt;।&lt;/li&gt;
	&lt;li data-end=&quot;272&quot; data-start=&quot;178&quot;&gt;&lt;strong data-end=&quot;204&quot; data-start=&quot;181&quot;&gt;फाइनल में प्लेयर ऑफ़ द मैच&lt;/strong&gt;: &lt;strong data-end=&quot;235&quot; data-is-only-node=&quot;&quot; data-start=&quot;219&quot;&gt;रोहित शर्मा&lt;/strong&gt; ने &lt;strong data-end=&quot;271&quot; data-start=&quot;252&quot;&gt;83 गेंदों पर 76 रन&lt;/strong&gt; बनाए।&lt;/li&gt;
	&lt;li data-end=&quot;347&quot; data-start=&quot;273&quot;&gt;&lt;strong data-end=&quot;310&quot; data-start=&quot;276&quot;&gt;टूर्नामेंट में सबसे अधिक विकेट&lt;/strong&gt;: &lt;strong data-end=&quot;326&quot; data-is-only-node=&quot;&quot; data-start=&quot;312&quot;&gt;मैट हेनरी&lt;/strong&gt; ने &lt;strong data-end=&quot;346&quot; data-start=&quot;332&quot;&gt;10 विकेट&lt;/strong&gt; लिए।&lt;/li&gt;
	&lt;li data-end=&quot;471&quot; data-start=&quot;348&quot;&gt;&lt;strong data-end=&quot;360&quot; data-start=&quot;351&quot;&gt;भारत&lt;/strong&gt; ने अपनी &lt;strong data-end=&quot;395&quot; data-is-only-node=&quot;&quot; data-start=&quot;369&quot;&gt;तीसरी चैंपियंस ट्रॉफी&lt;/strong&gt; का खिताब जीता, जो किसी भी टीम द्वारा सबसे अधिक है।&lt;/li&gt;
	&lt;li data-end=&quot;471&quot; data-start=&quot;348&quot;&gt;पिछली जीतें: &lt;strong data-end=&quot;426&quot; data-start=&quot;418&quot;&gt;2002&lt;/strong&gt; (श्रीलंका के साथ संयुक्त विजेता) और &lt;strong data-end=&quot;470&quot; data-start=&quot;462&quot;&gt;2013 (इंग्लैंड के खिलाफ)&lt;/strong&gt;।&lt;/li&gt;
	&lt;li data-end=&quot;535&quot; data-start=&quot;472&quot;&gt;&lt;strong data-end=&quot;501&quot; data-start=&quot;475&quot;&gt;पहली चैंपियंस ट्रॉफी&lt;/strong&gt; विजेता: &lt;strong data-end=&quot;526&quot; data-is-only-node=&quot;&quot; data-start=&quot;510&quot;&gt;दक्षिण अफ्रीका&lt;/strong&gt; 1998 में।&lt;/li&gt;
	&lt;li data-end=&quot;668&quot; data-start=&quot;536&quot;&gt;टूर्नामेंट का &lt;strong data-end=&quot;560&quot; data-start=&quot;543&quot;&gt;पहला संस्करण&lt;/strong&gt; &lt;strong data-end=&quot;607&quot; data-start=&quot;593&quot;&gt;बांग्लादेश&lt;/strong&gt; द्वारा &lt;strong data-end=&quot;619&quot; data-start=&quot;611&quot;&gt;1998&lt;/strong&gt; में आयोजित किया गया था और इसे शुरू में &lt;strong data-end=&quot;667&quot; data-start=&quot;651&quot;&gt;ICC नॉकआउट&lt;/strong&gt; के रूप में जाना जाता था।&lt;/li&gt;
	&lt;li data-end=&quot;733&quot; data-start=&quot;669&quot;&gt;&lt;strong data-end=&quot;705&quot; data-start=&quot;676&quot;&gt;ICC चैंपियंस ट्रॉफी 2025&lt;/strong&gt; की मेजबानी &lt;strong data-end=&quot;732&quot; data-start=&quot;720&quot;&gt;पाकिस्तान&lt;/strong&gt; ने की थी।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

