		&lt;tr style=&quot;height: 21px;&quot;&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;2009&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;ऑस्ट्रेलिया&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;न्यूज़ीलैंड&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;दक्षिण अफ्रीका&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr style=&quot;height: 21px;&quot;&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;2013&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;भारत&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;इंग्लैंड&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;इंग्लैंड और वेल्स&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr style=&quot;height: 21px;&quot;&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;2017&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;पाकिस्तान&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;भारत&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;इंग्लैंड और वेल्स&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr style=&quot;height: 21px;&quot;&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;2025&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;भारत&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;न्यूज़ीलैंड&lt;/td&gt;
			&lt;td style=&quot;border-color:  (204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;पाकिस्तान और UAE&lt;/td&gt;
		&lt;/tr&gt;
